https://roadtostudy.com/#person"},"inLanguage":"tr"},{"@type":"ImageObject","@id":"https://roadtostudy.com/wp-content/uploads/2025/04/part-time-student-employment-in-turkey.webp","url":"https://roadtostudy.com/wp-content/uploads/2025/04/part-time-student-employment-in-turkey.webp","width":"2336","height":"1760","caption":"Part-time job opportunities for students in Turkey","inLanguage":"tr"},{"@type":"WebPage","@id":"https://roadtostudy.com/turkiye-kismi-zamanli-calisma/#webpage","url":"https://roadtostudy.com/turkiye-kismi-zamanli-calisma/","name":"Türkiye&#039;de Kısmi Zamanlı Çalışma 2025: Öğrenci Rehberi","datePublished":"2025-04-29T10:54:37+03:00","dateModified":"2026-03-15T21:56:03+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"primaryImageOfPage":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/04/part-time-student-employment-in-turkey.webp"},"inLanguage":"tr"},{"@type":"Person","@id":"https://roadtostudy.com/author/murat/","name":"Murat","url":"https://roadtostudy.com/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"tr"}},{"@type":"BlogPosting","headline":"Türkiye&#039;de Kısmi Zamanlı Çalışma 2025: Öğrenci Rehberi","keywords":"kısmi zamanlı çalışma","datePublished":"2025-04-29T10:54:37+03:00","dateModified":"2026-03-15T21:56:03+03:00","articleSection":"Burslar ve Finansman","author":{"@id":"https://roadtostudy.com/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Türkiye&#039;de kısmi zamanlı çalışma ve öğrenci asistanlığı fırsatlarını keşfet! Şimdi başvuru şartlarını öğren ve eğitim hayatını destekle. Hemen tıkla!","name":"Türkiye&#039;de Kısmi Zamanlı Çalışma 2025: Öğrenci Rehberi","@id":"https://roadtostudy.com/turkiye-kismi-zamanli-calisma/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/turkiye-kismi-zamanli-calisma/#webpage"},"image":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/04/part-time-student-employment-in-turkey.webp"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/turkiye-kismi-zamanli-calisma/#webpage"}}]}]}', "content_html" = '<h2 class="wp-block-heading" id="turkiyede-kismi-zamanli-calisma-programi-nedir">Türkiye’de Kısmi Zamanlı Çalışma Programı Nedir?</h2>



<p class="wp-block-paragraph">Türkiye’de üniversite öğrencileri, sadece ders çalışmakla kalmayıp aynı zamanda kampüs içindeki bazı işlerde kısmi zamanlı olarak çalışabiliyor. Bu sistem, hem öğrencilerin ekonomik ihtiyaçlarını karşılamalarına hem de iş deneyimi kazanmalarına yardımcı oluyor.<br><a href="https://www.yok.gov.tr/Documents/Kurumsal/strateji_dairesi/mevzuat/Y%C3%9CKSEK%C3%96%C4%9ERET%C4%B0M%20KURUMLARI%20KISM%C4%B0%20ZAMANLI%20%C3%96%C4%9ERENC%C4%B0%20%C3%87ALI%C5%9ETIRMA%20USUL%20VE%20ESASLARI.pdf" target="_blank" rel="noopener">Yükseköğretim Kurulu (YÖK) tarafından belirlenen resmi mevzuat</a> doğrultusunda, her üniversite kendi kısmi zamanlı çalışma programını yürütüyor.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<h3 class="wp-block-heading" id="yuksekogretim-kurumlarinda-kismi-zamanli-ogrenci-calistirma-esaslari">Yükseköğretim Kurumlarında Kısmi Zamanlı Öğrenci Çalıştırma Esasları</h3>



<p class="wp-block-paragraph">Kısmi zamanlı çalışan öğrenciler için genel esaslar şunlar:</p>



<figure class="wp-block-table"><table class="has-fixed-layout"><thead><tr><th>Kriter</th><th>Açıklama</th></tr></thead><tbody><tr><td>Çalışma Süresi</td><td>Haftada en fazla 15 saat</td></tr><tr><td>Başvuru Şartı</td><td>Tam zamanlı öğrenci olmak ve aktif kaydı bulunmak</td></tr><tr><td>Öncelik</td><td>Ekonomik durumu yetersiz olan öğrenciler</td></tr></tbody></table></figure>



<p class="wp-block-paragraph">Bu kurallar çerçevesinde çalışılan alanlar genellikle kütüphaneler, idari ofisler, spor tesisleri veya öğrenci kulüplerinde oluyor.<br>Detaylı çalışma şartlarına örnek olarak <a href="https://sks.ankara.edu.tr/kismi-zamanli-calisma/#:~:text=2025%20Y%C4%B1l%C4%B1%20i%C3%A7in%201%20saatlik,kadar%20k%C4%B1smi%20zamanl%C4%B1%20%C3%B6%C4%9Frenci%20%C3%A7al%C4%B1%C5%9Ft%C4%B1rabilir." target="_blank" rel="noopener">Ankara Üniversitesi&#8217;nin kısmi zamanlı çalışma kurallarına</a> göz atabilirsin.</p>



<h3 class="wp-block-heading" id="haftalik-calisma-saatleri-ve-ucretler-2025-guncellemesi">Haftalık Çalışma Saatleri ve Ücretler 2025 Güncellemesi</h3>



<figure class="wp-block-table"><table class="has-fixed-layout"><thead><tr><th>Çalışma Süresi</th><th>Aylık Tahmini Brüt Ücret (USD)</th></tr></thead><tbody><tr><td>Haftada 10 saat çalışan bir öğrenci</td><td>Yaklaşık 122 USD</td></tr><tr><td>Haftada 15 saat çalışan bir öğrenci (maksimum)</td><td>Yaklaşık 182 USD</td></tr></tbody></table></figure>



<p class="wp-block-paragraph">Ancak unutma, maaşlar çalıştığın saatin miktarına ve birimin ücret politikasına göre değişebiliyor.<br>Kendi üniversitenin Sağlık, Kültür ve Spor Dairesi (SKS) web sitesinden güncel verileri mutlaka kontrol etmelisin.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<hr class="wp-block-separator has-alpha-channel-opacity"/>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<h2 class="wp-block-heading" id="ogrenci-asistanligi-gorevler-sartlar-ve-basvuru-sureci">Öğrenci Asistanlığı: Görevler, Şartlar ve Başvuru Süreci</h2>



<p class="wp-block-paragraph">Öğrenci asistanlığı, özellikle son sınıf lisans öğrencileri ile yüksek lisans ve doktora öğrencilerine yönelik daha akademik bir kısmi zamanlı iş fırsatı.<br>Benim arkadaşım mesela 4. sınıfta iken bir hocanın araştırma projesinde asistanlık yapmıştı ve gerçekten çok değerli bir deneyim kazandı.<br>Başvuru ve kabul süreci biraz daha resmi ve rekabetçi olabiliyor.</p>



<h3 class="wp-block-heading" id="hangi-ogrenciler-asistan-olabilir">Hangi Öğrenciler Asistan Olabilir?</h3>



<p class="wp-block-paragraph">Öğrenci asistanı olabilmek için genel şartlar şöyle:</p>



<ul class="wp-block-list">
<li>Akademik not ortalamasının üniversite tarafından belirlenen sınırın üstünde olması (genellikle min. 2.5/4.0)</li>



<li>Aktif öğrenci olmak (mezun olmamış olmak)</li>



<li>Derslerde veya araştırmalarda aktif görev alabilecek durumda olmak</li>



<li>Bazı birimler İngilizce yeterlilik veya belirli bir yazılım bilgisi de isteyebiliyor</li>
</ul>



<p class="wp-block-paragraph"><a href="https://roadtostudy.com/">Selçuk Üniversitesi&#8217;nin öğrenci asistanlığı başvuru detaylarını</a> da inceleyebilirsin.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<hr class="wp-block-separator has-alpha-channel-opacity"/>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<h2 class="wp-block-heading" id="kismi-zamanli-calisma-izni-uluslararasi-ogrenciler-icin-bilinmesi-gerekenler">Kısmi Zamanlı Çalışma İzni: Uluslararası Öğrenciler İçin Bilinmesi Gerekenler</h2>



<p class="wp-block-paragraph">Türkiye&#8217;de eğitim alan yabancı öğrenciler için kısmi zamanlı çalışmak bazı ek prosedürler gerektiriyor. &#8220;Sadece öğrenci vizesiyle çalışabiliyor muyum?&#8221; diye soran çok oluyor.<br>Kısaca cevap: Hayır, ekstra bir <strong>çalışma izni</strong> alman gerekiyor.</p>



<h3 class="wp-block-heading" id="calisma-izni-basvurusu-ve-yasal-mevzuat">Çalışma İzni Başvurusu ve Yasal Mevzuat</h3>



<p class="wp-block-paragraph">Türkiye&#8217;de uluslararası öğrenciler, öğrenimlerinin ilk yılından sonra çalışma iznine başvurabiliyorlar.<br>Başvuru için genellikle şunlar gerekiyor:</p>



<ul class="wp-block-list">
<li>Geçerli bir öğrenci ikamet izni</li>



<li>Bir işveren tarafından düzenlenen iş teklifi mektubu</li>



<li>Çalışma izni başvurusu</li>
</ul>



<p class="wp-block-paragraph">Çalışma izni olmadan çalışmak cezaya ve vize iptaline yol açabiliyor, dikkat etmek lazım.</p>



<h3 class="wp-block-heading" id="ogrenci-vizesi-sahiplerinin-haklari">Öğrenci Vizesi Sahiplerinin Hakları</h3>



<p class="wp-block-paragraph">Öğrenci vizesi sahipleri, sadece yarı zamanlı (part-time) işler için başvuru yapabiliyor.<br>Ayrıca çalışacakları yerin de resmi bir iş yeri olması gerekiyor. Freelance işler veya kayıtsız işlerde çalışmak yasal değil.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<hr class="wp-block-separator has-alpha-channel-opacity"/>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<h2 class="wp-block-heading" id="turkiyede-hangi-sehirlerde-ve-universitelerde-is-bulmak-kolay">Türkiye’de Hangi Şehirlerde ve Üniversitelerde İş Bulmak Kolay?</h2>



<p class="wp-block-paragraph">Bunu baştan söyleyeyim: Türkiye’de bazı şehirlerde kısmi zamanlı iş bulmak gerçekten çok daha kolay.<br>Özellikle büyük şehirlerde hem kampüs içi hem kampüs dışı iş fırsatları çok daha fazla.</p>



<h3 class="wp-block-heading" id="ankara-istanbul-izmir-kismi-zamanli-is-firsatlari">Ankara, İstanbul, İzmir: Kısmi Zamanlı İş Fırsatları</h3>



<p class="wp-block-paragraph">Bu üç şehir, öğrenci iş olanakları açısından adeta açık ara önde:</p>



<figure class="wp-block-table"><table class="has-fixed-layout"><thead><tr><th>Şehir</th><th>İş İmkanları</th><th>Popüler Üniversiteler</th></tr></thead><tbody><tr><td>İstanbul</td><td>Kütüphane, araştırma projeleri, kafeler, etkinlikler</td><td>Boğaziçi, İstanbul Üniversitesi, İstinye Üniversitesi</td></tr><tr><td>Ankara</td><td>Ofis destek işleri, kütüphane personeli, sosyal etkinlik organizasyonu</td><td>ODTÜ, Ankara Üniversitesi, Hacettepe Üniversitesi</td></tr><tr><td>İzmir</td><td>Öğrenci işleri ofisleri, etkinlik destek ekibi, sosyal medya yönetimi</td><td>Ege Üniversitesi, Dokuz Eylül Üniversitesi</td></tr></tbody></table></figure>



<p class="wp-block-paragraph">Örneğin <a href="https://ogrenciler.bogazici.edu.tr/Home/SubPage/kismizamanli" target="_blank" rel="noopener">Boğaziçi Üniversitesi&#8217;nin kısmi zamanlı iş programı</a> öğrencilere haftada maksimum 15 saatlik çalışma imkânı sağlıyor.</p>



<h3 class="wp-block-heading" id="universite-ici-birimler-ve-dis-isyeri-imkanlari">Üniversite İçi Birimler ve Dış İşyeri İmkanları</h3>



<p class="wp-block-paragraph">Üniversiteler içinde çalışabileceğin bazı birimler şöyle:</p>



<ul class="wp-block-list">
<li>Kütüphane ve dokümantasyon ofisleri</li>



<li>Spor salonları ve etkinlik merkezleri</li>



<li>Öğrenci işleri ve uluslararası ofisler</li>



<li>Bilgi işlem ve teknik destek ofisleri</li>
</ul>



<p class="wp-block-paragraph">Kampüs dışında ise kafe/restoran işleri, resepsiyonistlik, etkinlik organizasyon şirketlerinde görev almak gibi seçenekler var.<br>Özellikle İzmir ve İstanbul gibi turistik şehirlerde bu tarz iş bulmak daha da kolaylaşıyor.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<hr class="wp-block-separator has-alpha-channel-opacity"/>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<h2 class="wp-block-heading" id="kismi-zamanli-calismanin-artilari-ve-eksileri">Kısmi Zamanlı Çalışmanın Artıları ve Eksileri</h2>



<p class="wp-block-paragraph">Şimdi biraz gerçeklerden konuşalım:<br>Kısmi zamanlı çalışmanın elbette birçok avantajı var, ama birkaç zorluğu da yok değil.</p>



<h3 class="wp-block-heading" id="ekonomik-destek-ve-sosyal-hayata-etkileri">Ekonomik Destek ve Sosyal Hayata Etkileri</h3>



<p class="wp-block-paragraph">Artılar:</p>



<ul class="wp-block-list">
<li><strong>Gelir elde etmek</strong>: Kendi harçlığını kazanmanın özgüveni gerçekten paha biçilemez.</li>



<li><strong>İş deneyimi</strong>: Mezun olmadan CV&#8217;ne deneyim eklemek iş bulurken çok büyük avantaj sağlıyor.</li>



<li><strong>Yeni insanlarla tanışmak</strong>: Çalıştığın ortamda farklı bölümlerden, ülkelerden insanlarla tanışıyorsun.</li>
</ul>



<p class="wp-block-paragraph">Ben ilk kısmi zamanlı işime başladığımda, bir anda 20 kişilik yeni bir arkadaş grubum olmuştu. Özellikle yeni bir ülkedeysen, bu sosyalleşme fırsatı çok değerli oluyor.</p>



<h3 class="wp-block-heading" id="ders-basarisini-etkiler-mi">Ders Başarısını Etkiler mi?</h3>



<p class="wp-block-paragraph">Zorluklar:</p>



<ul class="wp-block-list">
<li><strong>Zaman yönetimi</strong>: Ders, sınav, iş&#8230; Üçünü birden dengelemek ciddi bir planlama gerektiriyor.</li>



<li><strong>Yorgunluk</strong>: Özellikle sınav dönemlerinde hem çalışıp hem ders yetiştirmek bazen bunaltıcı olabiliyor.</li>



<li><strong>Sınırlı iş seçeneği</strong>: Herkesin hayal ettiği işi bulması kolay değil. Bazı işler fiziksel olarak yorucu olabiliyor.</li>
</ul>



<p class="wp-block-paragraph">Bunun için küçük bir önerim: Ders yoğunluğun fazla olduğu dönemlerde çalışma saatlerini azaltmayı mutlaka önceden konuş.</p>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



<hr class="wp-block-separator has-alpha-channel-opacity"/>



<div style="height:22px" aria-hidden="true" class="wp-block-spacer"></div>



